"use strict";(self.webpackChunkjaspernote=self.webpackChunkjaspernote||[]).push([["86941"],{68719(n,e,a){a.r(e),a.d(e,{metadata:()=>t,default:()=>u,frontMatter:()=>o,contentTitle:()=>s,toc:()=>h,assets:()=>r});var t=JSON.parse('{"id":"java/basic/foundation/collection/map/hashmapSource","title":"hashmap \u6E90\u7801","description":"\u662Fjdk21\u7684\u6E90\u7801 \u4F46\u662F\u6574\u4F53\u903B\u8F91\u6CA1\u600E\u4E48\u53D8","source":"@site/docs/java/basic/foundation/collection/map/hashmapSource.md","sourceDirName":"java/basic/foundation/collection/map","slug":"/java/basic/foundation/collection/map/hashmapSource","permalink":"/jaspernote/docs/java/basic/foundation/collection/map/hashmapSource","draft":false,"unlisted":false,"editUrl":"https://github.com/facebook/docusaurus/tree/main/packages/create-docusaurus/templates/shared/docs/java/basic/foundation/collection/map/hashmapSource.md","tags":[],"version":"current","frontMatter":{},"sidebar":"javaBasic","previous":{"title":"HashMap","permalink":"/jaspernote/docs/java/basic/foundation/collection/map/HashMap"},"next":{"title":"arrayDeque","permalink":"/jaspernote/docs/java/basic/foundation/collection/queue/deque/ArrayDeque"}}'),l=a(74848),i=a(28453);let o={},s="hashmap \u6E90\u7801",r={},h=[];function d(n){let e={code:"code",h1:"h1",header:"header",img:"img",p:"p",pre:"pre",...(0,i.R)(),...n.components};return(0,l.jsxs)(l.Fragment,{children:[(0,l.jsx)(e.header,{children:(0,l.jsx)(e.h1,{id:"hashmap-\u6E90\u7801",children:"hashmap \u6E90\u7801"})}),"\n",(0,l.jsx)(e.p,{children:(0,l.jsx)(e.img,{src:a(40899).A+"",width:"3132",height:"2108"})}),"\n",(0,l.jsx)(e.p,{children:"\u662Fjdk21\u7684\u6E90\u7801 \u4F46\u662F\u6574\u4F53\u903B\u8F91\u6CA1\u600E\u4E48\u53D8"}),"\n",(0,l.jsx)(e.p,{children:"\u5148\u627E\u5230key\uFF0C\u627E\u5230\u5219\u8986\u76D6\uFF0C\u627E\u4E0D\u5230\u63D2\u5165\n\u5F53\u94FE\u8868\u957F\u5EA6>=8 \u5E76\u4E14table>= 64 \u5219\u6811\u5316\n\u5F53size\u300Bcapacity*loadFactor \u6269\u5BB9"}),"\n",(0,l.jsx)(e.pre,{children:(0,l.jsx)(e.code,{className:"language-java",children:'    /**\n     * The default initial capacity - MUST be a power of two.\n     * \u8BA1\u7B97\u6570\u7EC4\u4E0B\u6807\n     * i = (n - 1) & hash   n-1=15&hash = 1111&hash   \u5982\u679C\u4E0D\u662F2\u7684\u5E42\uFF1An=10 n-1=9  1001 \u5206\u5E03\u4F1A\u5F88\u4E0D\u5747\u8861 \n     * \u8FD9\u91CC\u53EA\u7528\u4E86\u4F4E\u4F4D\n     */\n    static final int DEFAULT_INITIAL_CAPACITY = 1 << 4; // aka(also known as \u4E5F\u5C31\u662F) 16  0001   1 0000 2^4\n\n    /**\n     * The maximum capacity, used if a higher value is implicitly specified\n     * by either of the constructors with arguments.\n     * MUST be a power of two <= 1<<30.\n     */\n    static final int MAXIMUM_CAPACITY = 1 << 30; //aka 1073741824\n\n    /**\n     * The load factor used when none specified in constructor.\n     * \u5982\u679C\u8BBE\u4E3A 1.0\uFF1A \u7A7A\u95F4\u5229\u7528\u7387\u6781\u9AD8\uFF0C\u4F46\u5FC5\u987B\u7B49\u5230\u6876\u5168\u6EE1\u624D\u6269\u5BB9\u3002\u8FD9\u4F1A\u5BFC\u81F4\u5728\u63A5\u8FD1 1.0 \u65F6\u53D1\u751F\u5927\u91CF\u7684\u54C8\u5E0C\u78B0\u649E\uFF0C\u67E5\u8BE2\u6027\u80FD\u5927\u5E45\u4E0B\u964D\n     */\n    static final float DEFAULT_LOAD_FACTOR = 0.75f;\n\n    /**\n     * The bin count threshold for using a tree rather than list for a\n     * bin.  Bins are converted to trees when adding an element to a\n     * bin with at least this many nodes. The value must be greater\n     * than 2 and should be at least 8 to mesh with assumptions in\n     * tree removal about conversion back to plain bins upon\n     * shrinkage.\n     */\n    static final int TREEIFY_THRESHOLD = 8;\n\n    /**\n     * The bin count threshold for untreeifying a (split) bin during a\n     * resize operation. Should be less than TREEIFY_THRESHOLD, and at\n     * most 6 to mesh with shrinkage detection under removal.\n     */\n    static final int UNTREEIFY_THRESHOLD = 6;\n\n    /**\n     * The smallest table capacity for which bins may be treeified.\n     * (Otherwise the table is resized if too many nodes in a bin.)\n     * Should be at least 4 * TREEIFY_THRESHOLD to avoid conflicts\n     * between resizing and treeification thresholds.\n     */\n    static final int MIN_TREEIFY_CAPACITY = 64;\n\n    transient Node<K,V>[] table;\n    /**\n     * \u94FE\u8868\u4E2D\u7684\u4E00\u4E2A\u8282\u70B9\n     * Basic hash bin node, used for most entries.  (See below for\n     * TreeNode subclass, and in LinkedHashMap for its Entry subclass.)\n     */\n    static class Node<K,V> implements Map.Entry<K,V> {\n        final int hash;\n        final K key;\n        V value;\n        Node<K,V> next;\n\n        Node(int hash, K key, V value, Node<K,V> next) {\n            this.hash = hash;\n            this.key = key;\n            this.value = value;\n            this.next = next;\n        }\n\n        public final K getKey()        { return key; }\n        public final V getValue()      { return value; }\n        public final String toString() { return key + "=" + value; }\n\n        public final int hashCode() {\n            return Objects.hashCode(key) ^ Objects.hashCode(value);\n        }\n\n        public final V setValue(V newValue) {\n            V oldValue = value;\n            value = newValue;\n            return oldValue;\n        }\n\n        public final boolean equals(Object o) {\n            if (o == this)\n                return true;\n\n            return o instanceof Map.Entry<?, ?> e\n                    && Objects.equals(key, e.getKey())\n                    && Objects.equals(value, e.getValue());\n        }\n    }\n\n    static final int hash(Object key) {\n        int h;\n        // \u65E0\u7B26\u53F7\u53F3\u79FB \u76F4\u63A5\u88650 \n// h        = 1010 0000 0000 0000 0000 0000 0000 1111\n// h >>> 16 = 0000 0000 0000 0000 1010 0000 0000 0000\n// \u8BA9\u9AD8\u4F4D\u53C2\u4E0E\u4F4E\u4F4D\u8FD0\u7B97\uFF0C\u907F\u514Dhash\u51B2\u7A81\n// \u5BF9hashcode\u505A\u6270\u52A8 \u8BA9\u54C8\u5E0C\u5206\u5E03\u66F4\u52A0\u5747\u5300\n        return (key == null) ? 0 : (h = key.hashCode()) ^ (h >>> 16);\n    }\nfinal V putVal(int hash, K key, V value, boolean onlyIfAbsent,\n                   boolean evict) {\n      // \u6570\u7EC4             \u94FE\u8868 \u7B2C\u4E00\u4E2A\u8282\u70B9 \n        Node<K,V>[] tab; Node<K,V> p; int n, i;\n      // \u61D2\u52A0\u8F7D \u7B2C\u4E00\u6B21put\u624D\u521D\u59CB\u5316\n        if ((tab = table) == null || (n = tab.length) == 0)\n            n = (tab = resize()).length;\n      // \u8BA1\u7B97\u6570\u7EC4\u4E0B\u6807 \u6CA1\u6709\u51B2\u7A81\u76F4\u63A5\u63D2\u5165\n        if ((p = tab[i = (n - 1) & hash]) == null)\n            tab[i] = newNode(hash, key, value, null);\n        // \u6709\u51B2\u7A81\n        else {\n        // e \u4E0B\u4E00\u4E2A\u8282\u70B9 p \u5F53\u524D\u8282\u70B9\n            Node<K,V> e; K k;\n        //  key \u5DF2\u7ECF\u5B58\u5728 \u540E\u9762\u4F1A\u8986\u76D6\u65E7\u503C    \u5F15\u7528\u6216\u8005\u5185\u5BB9\n            if (p.hash == hash && ((k = p.key) == key || (key != null && key.equals(k))))\n                e = p;\n        // rbtree\n            else if (p instanceof TreeNode)\n                e = ((TreeNode<K,V>)p).putTreeVal(this, tab, hash, key, value);\n            else {\n          // linkedlist\n                for (int binCount = 0; ; ++binCount) {\n            // \u94FE\u8868\u5C3E\u90E8 \u63D2\u5165 p = \u94FE\u8868\u4E2D\u7B2C\u4E00\u4E2A\u5143\u7D20\n                    if ((e = p.next) == null) {\n                        p.next = newNode(hash, key, value, null);\n                        if (binCount >= TREEIFY_THRESHOLD - 1) // -1 for 1st \u94FE\u8868\u957F\u5EA6>8 \u5219\u6811\u5316 tab \u8981\u5C0F\u4E8E64\n                            treeifyBin(tab, hash);\n                        break;\n                    }\n            // \u5224\u65AD\u94FE\u8868\u4E2D\u6709\u6CA1\u6709\u91CD\u590D\u7684\n                    if (e.hash == hash &&\n                        ((k = e.key) == key || (key != null && key.equals(k))))\n                        break;\n                    p = e;\n                }\n            }\n        // \u8986\u76D6\u65E7\u503C\n            if (e != null) { // existing mapping for key\n                V oldValue = e.value;\n          // hashmap \u5141\u8BB8\u503C\u4E3Anull\n                if (!onlyIfAbsent || oldValue == null)\n                    e.value = value;\n          // \u7ED9linkedhashmap\u7528\u7684  \u8282\u70B9\u88AB\u8BBF\u95EE\u4E4B\u540E\u7528\u7684\n                afterNodeAccess(e);\n                return oldValue;\n            }\n        }\n      // \u8BB0\u5F55 HashMap \u88AB\u201C\u7ED3\u6784\u6027\u4FEE\u6539\u201D\u7684\u6B21\u6570\uFF0C\u7528\u4E8E\u8FED\u4EE3\u5668\u68C0\u6D4B\u5E76\u53D1\u4FEE\u6539\uFF08fail-fast\uFF09\n      // scene \u4E00\u904D\u904D\u5386 \u4E00\u904D\u4FEE\u6539\u7ED3\u6784   HashIterator\n        ++modCount;\n        if (++size > threshold)\n            resize();\n      // \u7ED9linkedhashmap\u7528\u7684 \u8282\u70B9\u88AB\u63D2\u5165\u4E4B\u540E\u7528\u7684 \u5220\u9664\u6700\u8001\u7684\u8282\u70B9  \u5B9E\u73B0lru   removeEldestEntry\n      // template method design pattern \n        afterNodeInsertion(evict);\n        return null;\n    }\nfinal Node<K,V>[] resize() {\n      // \u65E7\u6570\u7EC4\n        Node<K,V>[] oldTab = table;\n      // \u65E7\u5BB9\u91CF\n        int oldCap = (oldTab == null) ? 0 : oldTab.length;\n      // \u65E7\u6269\u5BB9\u9608\u503C capacity*loadFactor\n        int oldThr = threshold;\n        int newCap, newThr = 0;\n        if (oldCap > 0) {// \u521D\u59CB\u5316\u8FC7\n            if (oldCap >= MAXIMUM_CAPACITY) {\n                threshold = Integer.MAX_VALUE;\n                return oldTab; // \u5230\u6700\u5927\u5BB9\u91CF\u76F4\u63A5\u8FD4\u56DE\u65E7\u6570\u7EC4\n            }\n            else if ((newCap = oldCap << 1) < MAXIMUM_CAPACITY &&\n                     oldCap >= DEFAULT_INITIAL_CAPACITY)\n                newThr = oldThr << 1; // double threshold\n        // \u5BB9\u91CF\u548C\u9608\u503C\u90FD\u7FFB\u500D\n        }\n      // \u6709thresold \u4F46\u662Ftable\u8FD8\u6CA1\u6709\u5EFA new HashMap(16)\n        else if (oldThr > 0) // initial capacity was placed in threshold\n            newCap = oldThr;//threshold \u4EE3\u7406\u4E86 capacity \u7684\u804C\u8D23 tableSizeFor\n      // new HashMap()\n        else {               // zero initial threshold signifies using defaults\n            newCap = DEFAULT_INITIAL_CAPACITY;//16 \n            newThr = (int)(DEFAULT_LOAD_FACTOR * DEFAULT_INITIAL_CAPACITY);//16*0.75=12\n        }\n        if (newThr == 0) {\n            float ft = (float)newCap * loadFactor;\n            newThr = (newCap < MAXIMUM_CAPACITY && ft < (float)MAXIMUM_CAPACITY ?\n                      (int)ft : Integer.MAX_VALUE);\n        }\n        threshold = newThr;\n        @SuppressWarnings({"rawtypes","unchecked"})\n        Node<K,V>[] newTab = (Node<K,V>[])new Node[newCap];\n        table = newTab;\n      // \u8FC1\u79FB\u6570\u636E\n        if (oldTab != null) {\n            for (int j = 0; j < oldCap; ++j) {\n                Node<K,V> e;\n                if ((e = oldTab[j]) != null) {\n                    oldTab[j] = null;// \u65AD\u5F00\u5F15\u7528 \u5E2E\u52A9gc\n                    if (e.next == null)// \u6CA1\u6709\u94FE\u8868 \u5355\u8282\u70B9\n            // p = tab[i = (n - 1) & hash]) \u91CD\u65B0\u8BA1\u7B97\u4F4D\u7F6E\n                        newTab[e.hash & (newCap - 1)] = e;\n                    else if (e instanceof TreeNode) // \u662Frbtree\n                        ((TreeNode<K,V>)e).split(this, newTab, j, oldCap);\n                    else { // preserve order \u94FE\u8868\n                        Node<K,V> loHead = null, loTail = null;//\u539F\u4F4D\u7F6E\n                        Node<K,V> hiHead = null, hiTail = null;//\u65B0\u4F4D\u7F6E\n                        Node<K,V> next;\n                        do {\n                            next = e.next;// \u4FDD\u5B58\u4E0B\u4E00\u4E2A\u8282\u70B9 \u9632\u6B62\u65AD\u94FE\n                          /*\noldIndex = hash & (oldCapacity - 1)\nnewIndex = hash & (oldCapacity*2 - 1)\n16 -> 32   01111 -> 11111  \u53EA\u591A\u4E86\u4E00\u4E2A\u9AD8\u4F4D1\n                         */\n                            if ((e.hash & oldCap) == 0) {// \u9AD8\u4F4D=0 \u7559\u5728\u539F\u4F4D\u7F6E\n                                if (loTail == null)\n                                    loHead = e;\n                                else\n                                    loTail.next = e;\n                                loTail = e;\n                            }\n                            else {// \u9AD8\u4F4D = 1 \u53BB\u65B0\u7684\u4F4D\u7F6E \n                                if (hiTail == null)\n                                    hiHead = e;\n                                else\n                                    hiTail.next = e;\n                                hiTail = e;\n                            }\n                        } while ((e = next) != null);\n                        if (loTail != null) {\n                            loTail.next = null;\n                            newTab[j] = loHead;// \u539F\u4F4D\u7F6E\n                        }\n                        if (hiTail != null) {\n                            hiTail.next = null;\n                            newTab[j + oldCap] = hiHead;//\u65B0\u4F4D\u7F6E\n                        }\n                    }\n                }\n            }\n        }\n        return newTab;\n    }\n\n    // binCount >= TREEIFY_THRESHOLD - 1 = 7\n    final void treeifyBin(Node<K,V>[] tab, int hash) {\n        int n, index; Node<K,V> e;\n        if (tab == null || (n = tab.length) < MIN_TREEIFY_CAPACITY)//64\n            resize();\n        else if ((e = tab[index = (n - 1) & hash]) != null) {\n            TreeNode<K,V> hd = null, tl = null;\n            do {\n                TreeNode<K,V> p = replacementTreeNode(e, null);\n                if (tl == null)\n                    hd = p;\n                else {\n                    p.prev = tl;\n                    tl.next = p;\n                }\n                tl = p;\n            } while ((e = e.next) != null);\n            if ((tab[index] = hd) != null)\n                hd.treeify(tab);\n        }\n    }\n'})})]})}function u(n={}){let{wrapper:e}={...(0,i.R)(),...n.components};return e?(0,l.jsx)(e,{...n,children:(0,l.jsx)(d,{...n})}):d(n)}},40899(n,e,a){a.d(e,{A:()=>t});let t=a.p+"assets/images/hashmapstructure-dd1e7d8372e22e66043a421aebad9bb2.png"},28453(n,e,a){a.d(e,{R:()=>o,x:()=>s});var t=a(96540);let l={},i=t.createContext(l);function o(n){let e=t.useContext(i);return t.useMemo(function(){return"function"==typeof n?n(e):{...e,...n}},[e,n])}function s(n){let e;return e=n.disableParentContext?"function"==typeof n.components?n.components(l):n.components||l:o(n.components),t.createElement(i.Provider,{value:e},n.children)}}}]);